INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation, order_index) VALUES
('7603b416-bd52-426d-b462-d3f9f130c5d3', 'Điền liên từ: ''Would you like tea ___ coffee?''', 'multiple_choice', '["and","or","but","so"]'::jsonb, 'or', '''Or'' chỉ sự lựa chọn (hoặc).', 1),
('34ae0783-6f59-4803-b573-d6a2a0011797', 'Điền liên từ: ''He went to work ___ he was sick.''', 'multiple_choice', '["because","although","so","and"]'::jsonb, 'although', '''Although'' (mặc dù) diễn tả sự nhượng bộ.', 1),
('958d3fe4-3f33-49df-9dca-39be4838a57c', 'Điền từ: ''___ my brother and I like playing football.''', 'multiple_choice', '["Both","Either","Neither","Not only"]'::jsonb, 'Both', 'Cấu trúc ''Both A and B'' (Cả A và B).', 1),
('f5ceab96-d679-4696-a39f-ab41f7eaee14', 'Điền liên từ thích hợp: ''I was tired, ___ I went to bed early.''', 'multiple_choice', '["so","but","because","although"]'::jsonb, 'so', '''So'' chỉ kết quả (vì vậy).', 1),
('111ffbae-8100-4bc8-86e7-8bf637abd98d', 'So sánh bất quy tắc của ''good'' là gì?', 'multiple_choice', '["gooder","better","best","more good"]'::jsonb, 'better', '''Good'' chuyển sang so sánh hơn là ''better''.', 1),
('580b7d5b-b6b6-44c5-88b8-8b23b510bcf4', 'So sánh hơn tính từ dài: ''This book is ___ interesting than that one.''', 'multiple_choice', '["more","much","most","many"]'::jsonb, 'more', 'Cấu trúc ''more + adj dài + than''.', 1),
('759e68c4-b334-4235-ae17-ff6cb77828ad', 'So sánh hơn tính từ ngắn: ''My house is ___ than yours.''', 'multiple_choice', '["big","biger","bigger","more big"]'::jsonb, 'bigger', 'Gấp đôi phụ âm cuối rồi thêm -er thành ''bigger''.', 1),
('1ef00f18-1052-4ae6-94d0-6f6a58d0308d', 'So sánh nhất tính từ dài: ''She is the ___ beautiful girl in my class.''', 'multiple_choice', '["more","most","much","very"]'::jsonb, 'most', 'Cấu trúc ''the most + adj dài''.', 1),
('c77d06e2-9ebf-42d1-b134-3816355e4661', 'So sánh nhất tính từ ngắn: ''He is the ___ student in the school.''', 'multiple_choice', '["tallest","tall","taller","most tall"]'::jsonb, 'tallest', 'Thêm đuôi -est vào tính từ ngắn.', 1),
('e94c6834-73b9-44c1-8f20-f519fd21d718', 'Chọn câu sai ngữ pháp:', 'multiple_choice', '["He is taller than me.","She is the most smart.","This car is more expensive.","It''s the best day."]'::jsonb, 'She is the most smart.', '''Smart'' là tính từ ngắn nên phải dùng ''smartest'', không dùng ''most smart''.', 1),
('a5157126-a9b0-4d9c-b1e5-82e191d90033', 'Phrasal verb ''get up'' có nghĩa là gì?', 'multiple_choice', '["Đi ngủ","Thức dậy","Vào trong","Đi ra ngoài"]'::jsonb, 'Thức dậy', '''Get up'' nghĩa là thức dậy rời khỏi giường.', 1),
('18334652-2670-454e-91d2-e978cb1f6e29', 'Xe ô tô của bạn bị hỏng giữa đường, bạn dùng từ nào?', 'multiple_choice', '["break out","break down","carry on","carry out"]'::jsonb, 'break down', '''Break down'' dùng khi máy móc, xe cộ bị hỏng.', 1),
('9a07fdd6-0b32-4915-95f6-54230bad537b', 'Khi nhận phòng khách sạn, bạn cần làm thủ tục gì?', 'multiple_choice', '["check out","check in","call off","call back"]'::jsonb, 'check in', '''Check in'' là làm thủ tục nhận phòng.', 1),
('5fa96e68-f982-46d5-8c92-5e14add03791', 'Điền từ: ''Please ___ on. Don''t stop reading.''', 'multiple_choice', '["go","come","get","take"]'::jsonb, 'go', '''Go on'' có nghĩa là tiếp tục (continue).', 1),
('a34b9ad6-3a61-415c-ae16-b250dcaeb2f2', 'Từ bỏ một thói quen xấu (ví dụ hút thuốc), bạn dùng từ nào?', 'multiple_choice', '["make up","give up","make out","give in"]'::jsonb, 'give up', '''Give up'' là từ bỏ.', 1),
('cc283f34-edc4-483e-8390-a57540e76591', 'Chăm sóc trẻ em bằng tiếng Anh là gì?', 'multiple_choice', '["look for","look at","look after","look up"]'::jsonb, 'look after', '''Look after'' nghĩa là chăm sóc, trông nom.', 1),
('e8478114-4e61-467e-b195-f79178fd03a7', 'Đón ai đó bằng xe, bạn dùng cụm nào?', 'multiple_choice', '["pick up","set up","run out","run away"]'::jsonb, 'pick up', '''Pick up'' dùng với nghĩa đón ai đó.', 1),
('0e90d13b-00f4-4ce3-87c5-748054972421', 'Máy bay cất cánh, bạn dùng phrasal verb nào?', 'multiple_choice', '["take on","take off","take in","take over"]'::jsonb, 'take off', '''Take off'' là cất cánh.', 1),
('30e7e6a0-c2b0-4d63-bdf3-66de6ec0998f', 'Mặc quần áo vào, bạn dùng cụm từ nào?', 'multiple_choice', '["put off","put on","turn on","turn off"]'::jsonb, 'put on', '''Put on'' là mặc đồ, mang giày, đội mũ.', 1),
('5b47891e-cc7e-43a1-a566-87b49491d418', 'Khi chuông báo thức reo, động từ nào mô tả tiếng reo đó?', 'multiple_choice', '["goes off","goes on","turns up","takes off"]'::jsonb, 'goes off', '''Go off'' mang nghĩa nổ tung, hoặc chuông reo.', 1);